#include <iostream>
#include <string>
#include <cmath>

using namespace std;

// Problem: Codeforces Round 299 (Div. 2), B - Tavas and SaDDas
// Link: https://codeforces.com/contest/535/problem/B
//
// Summary:
// Given a lucky number made only of digits 4 and 7, find its 1-based position
// in the increasing sequence of all lucky numbers.
//
// Solve:

// Through permutations, all lucky numbers with k digits can be formed.
// Therefore, position(n) = count of lucky numbers with fewer digits + position within the k-digit group, where k = get_cypher(n).

// If we analyze the k-digit lucky numbers in order:
// 444 447 474 477 744 747 774 777, they strongly resemble the binary system:
// 000 001 010 011 100 101 110 111. Their binary representation matches their
// position among the k-digit lucky numbers + 1.

// The sum of positions up to x digits is SUM 2^i (i: 1 -> (get_cypher(n) - 1)) = 1U << get_cypher(n) - 2.

//if(s[i] == '4') ret_bin = ret_bin << 1 + 0;
//else ret_bin = ret_bin << 1 + 1;

size_t get_bin(size_t num) {
    string s = to_string(num);
    size_t ret_bin = 0;
    for (auto it = s.begin(); it != s.end(); ++it)
    {
        if(*it == '4') ret_bin = ret_bin << 1;
        else ret_bin = (ret_bin << 1) + 1;
    }
    return ret_bin;
}

size_t get_cypher(size_t num) {
    return 1 + log10(num);
}

int main() {
    size_t n; cin >> n;
    size_t sum_position = (1U << get_cypher(n)) - 2;
    size_t position_relative = 1 + get_bin(n);
    size_t position = sum_position + position_relative;

    cout << position << endl;

    return 0;
}

codeforces_div_2_round_332_problem_d:
#include <iostream>
#include <vector>

using namespace std;
#define LL long long

// Problem: Codeforces Round 332 (Div. 2), D - Spongebob and Squares
// Link: https://codeforces.com/contest/599/problem/D
//
// Summary:
// Given x, find all grid dimensions n by m such that the total number of square
// subrectangles in the grid is exactly x.
//
// Solve:
// Squares range from size 1 to min_side and extend across max_side.

// It is only necessary to analyze combinations with n < m, so total = analysis * 2.

// Horizontal square density: 1 + max_side - side = 1 + c_2 - side
// Vertical square density: 1 + min_side - side = 1 + c_1 - side

// side 1 -> min_side
// Squares = SUM (1 + c_1 - side) * (1 + c_2 - side)
// Squares = SUM ((1+c_1)*(1+c_2) - (2+c_1+c_2)*side + side*side)
// Squares = (1+c_1)*(1+c_2)*c_1 - (2+c_1+c_2)*c_1*(1+c_1)/2 + c_1*(1+c_1)*(2*c_1+1)/6
// Squares = c_1*(1+c_1)*(1+3*c_2 -c_1)/6

// Get c_2 as a function of c_1 and squares.
// c_2 = (c_1 + (squares*6)/(c_1*(c_1+1)) - 1) / 3
// min_c_1 = 1
// It is not necessary to determine the maximum; it is enough to know it will be found in O(n^(1/3)).
// Iterate while c_1 < c_2 (c_1 = n, c_2 = m for n <= m).

LL get_c_2(LL squares, LL c_1) {
    return (c_1 + (squares*6)/(c_1*(c_1+1)) - 1) / 3;
}

bool verify_squares(LL squares, LL c_1, LL c_2) {
    LL a = squares*6;
    LL b = c_1*(1+c_1)*(1+3*c_2 -c_1);
    return a == b;
}


int main() {
    LL squares; cin >> squares;
    bool continue_flag = true;
    vector<LL> n_array;
    vector<LL> m_array;
    size_t counting_cases = 0;

    for (LL n = 1; continue_flag; n++)
    {
        LL m = get_c_2(squares, n);
        if(n > m) continue_flag = false;
        else if(verify_squares(squares,n,m)) {
            n_array.push_back(n);
            m_array.push_back(m);
            counting_cases++;
        }
    }
    bool state_case = n_array[counting_cases-1] == m_array[counting_cases-1];
    size_t real_cases = counting_cases*2;
    size_t second_iter = counting_cases;
    if(state_case) {
        real_cases--;
        second_iter--;
    }
    cout << real_cases << endl;
    for (size_t i = 0; i < counting_cases; i++)
    {
        cout << n_array[i] << " " << m_array[i] << endl;
    }
    for (size_t i = second_iter; i > 0; i--)
    {
        cout << m_array[i-1] << " " << n_array[i-1] << endl;
    }
    return 0;
}

codeforces_div_2_round_357_problem_b:
#include <iostream>

using namespace std;

#define A 1234567
#define B 123456
#define C 1234

// Problem: Codeforces Round 357 (Div. 2), B - Economy Game
// Link: https://codeforces.com/contest/681/problem/B
//
// Summary:
// Given n, determine whether it can be represented as a non-negative sum of
// 1234567, 123456, and 1234.
//
// Solve:
// With many coefficients, it is better to iterate a DP array over every possible formation in O(n).
// With few coefficients, it is better to iterate over them and check the remainder against the last one in O(A*B).

int main() {
    size_t n; cin >> n;
    bool flag = false;
    for (size_t i = 0; i <= n && !flag; i+=A)
    {
        for (size_t j = 0; j <= (n-i) && !flag; j+=B)
        {
            if((n-i-j)%C == 0) flag = true;
        }
    }
    if(flag) cout << "YES" << endl;
    else cout << "NO" << endl;

    return 0;
}

codeforces_div_2_round_511_problem_a:
#include <iostream>

using namespace std;

#define N 3

// Problem: Codeforces Round 511 (Div. 2), A - Little C Loves 3 I
// Link: https://codeforces.com/contest/1047/problem/A
//
// Summary:
// Given n, split it into three positive integers whose sum is n and none of
// them is divisible by 3.
//
// Solve:
// Aim for one maximum number, keep the rest minimal, and distribute the remainder across all of them.
// new_n = (n / 3) * 3
// res = n % 3
// a = new_n; b = 0; c = 0

// Notice that new_n will always be greater than or equal to 3.
// Distribute the remainder among the 3 numbers so none of them is a multiple of 3.

// The real question is how to distribute the remainder.
// Example when distributing 0:
// -2 1 1
// Example when distributing 1:
// -1 1 1
// Example when distributing 2:
// -1 2 1

int main() {
    size_t n; cin >> n;
    size_t new_n = (n / 3) * 3;
    size_t res = n % 3;
    size_t a = new_n, b = 0, c = 0;
    switch (res)
    {
    case 0:
        a -= 2; b++; c++;
        break;
    case 1:
        a -= 1; b++; c++;
        break;
    case 2:
        a -= 1; b+=2; c++;
        break;
    default:
        break;
    }
    cout << a << " " << b << " " << c << endl;

    return 0;
}

codeforces_div_2_round_672_problem_b:
#include <iostream>
#include <vector>

using namespace std;

#define N_CYPHER 32

size_t get_cypher(size_t num) {
    return 32 - __builtin_clz(num);
}

// Problem: Codeforces Round 672 (Div. 2), B - Rock and Lever
// Link: https://codeforces.com/contest/1420/problem/B
//
// Summary:
// Count pairs of indices (i, j), i < j, such that a[i] & a[j] is greater than
// or equal to a[i] xor a[j].
//
// Solve:
// Numbers satisfy the condition exactly when they have the same most significant
// bit. Count how many numbers belong to each bit-length group, then add
// count * (count - 1) / 2 for every group.
// Order does not matter because the operation and condition are symmetric. For
// numbers with the same number of bits, both have the same leading 1 bit, so the
// bitwise AND keeps that high bit while XOR cannot exceed it. Numbers from
// different bit-length groups do not satisfy the condition.

int main() {
    size_t t; cin >> t;
    for (size_t iter_t = 0; iter_t < t; iter_t++)
    {
        size_t n; cin >> n;
        vector<size_t> counting_cypher_groups(N_CYPHER,0);
        for (size_t i = 0; i < n; i++)
        {
            size_t num; cin >> num;
            counting_cypher_groups[get_cypher(num)]++;
        }
        size_t solve = 0;
        for (size_t i = 0; i < N_CYPHER; i++)
        {
            solve += counting_cypher_groups[i] * (counting_cypher_groups[i]-1) / 2;
        }
        cout << solve << endl;
    }

    return 0;
}

