#include <algorithm>
#include <iostream>
#include <vector>
using namespace std;

// Problem: Codeforces Round 936 (Div. 2), A - Median of an Array
// Link: https://codeforces.com/contest/1946/problem/A
//
// Summary:
// For each test case, an array of n integers is given. For this problem, the
// median is the element at index (n - 1) / 2 after sorting the array in
// non-decreasing order.
// In one operation, any single element can be increased by 1. The goal is to
// find the minimum number of operations needed to make the array median
// strictly larger than its initial value.
//
// Solve:
// Use nth_element to place the median in the same position it would have after
// sorting. To increase the median, every value equal to it from the median
// position to the right must be increased at least once. The answer is how many
// of those median values appear in the array.

int main() {
	int t; cin >> t;
	while (t--)
	{
		int n; cin >> n;
		vector<int> array_n(n);
		for (int i = 0; i < n; i++)
		{
			cin >> array_n[i];
		}

		int middle = (n - 1) / 2;
		nth_element(array_n.begin(), array_n.begin() + middle, array_n.end());

		int median = array_n[middle];
		int sol = 0;
		for (int i = middle; i < n; i++)
		{
			if (array_n[i] == median) sol++;
		}

		cout << sol << endl;
	}
	return 0;
}

codeforces_div_2_round_940_problem_b:
#include <iostream>
#include <cmath>
using namespace std;

// Problem: Codeforces Round 940 (Div. 2), B - A BIT of a Construction
// Link: https://codeforces.com/contest/1957/problem/B
//
// Summary:
// For each test case, construct an array of n non-negative integers whose sum is
// exactly k. Among all valid arrays, the goal is to maximize the number of
// 1 bits in the bitwise OR of all array elements. Any array that reaches that
// maximum is accepted.
//
// Solve:
// If n is 1, the only possible array is [k]. Otherwise, build sol with the same
// binary length as k, but with the MSB as 0 and every lower bit as 1. For
// example, if k is 128 (10000000 in binary), sol is 127 (01111111 in binary).
// The second number is k - sol, and the rest is filled with zeroes.

int main() {
	int t; cin >> t;
	while (t--)
	{
		int n; int k; cin >> n >> k;
		if (n == 1) cout << k << endl;
		else {
			int n_bits = log2(k);
			int sol = pow(2, n_bits) - 1;
			cout << sol << " " << (k - sol) << " ";
			for (int j = 2; j < n; j++)
			{
				cout << 0 << " ";
			}
			cout << endl;
		}
	}
	return 0;
}

codeforces_div_2_round_951_problem_a:
#include <algorithm>
#include <iostream>
#include <vector>
using namespace std;

// Problem: Codeforces Round 951 (Div. 2), A - Guess the Maximum
// Link: https://codeforces.com/contest/1979/problem/A
//
// Summary:
// For each test case, an array is given. We need choose an integer k such that
// every subarray with length at least 2 has a maximum value greater than k. The
// goal is to find the maximum possible k.
//
// Solve:
// Any subarray with length at least 2 contains at least one adjacent pair.
// Therefore, the limiting case is the adjacent pair with the smallest maximum.
// If min_pair_max is the minimum value among max(a[i], a[i + 1]), then k must
// be strictly smaller than that value. So the answer is min_pair_max - 1.

int main() {
	int t; cin >> t;
	while (t--) {
		int n; cin >> n;
		vector<int> array_n(n);
		for (int i = 0; i < n; i++)
		{
			cin >> array_n[i];
		}
		int min_pair_max = max(array_n[0], array_n[1]);
		for (int i = 1; i < (n-1); i++)
		{
			int pair_max = max(array_n[i], array_n[i + 1]);
			if (pair_max < min_pair_max) min_pair_max = pair_max;
		}
		cout << (min_pair_max - 1) << endl;
	}
	return 0;
}

codeforces_div_2_round_951_problem_c:
#include <iostream>
#include <numeric>
#include <vector>
using namespace std;

// Problem: Codeforces Round 951 (Div. 2), C - Earning on Bets
// Link: https://codeforces.com/contest/1979/problem/C
//
// Summary:
// For each test case, there are n possible betting outcomes. If outcome i wins,
// every coin placed on it is multiplied by k[i]. We need choose a positive
// number of coins for each outcome so that, no matter which outcome wins, the
// payout is strictly greater than the total number of coins placed. If no valid
// distribution exists, print -1.
//
// Solve:
// Let total be the sum of all placed coins. For every outcome i, we need
// coins[i] * k[i] > total. A useful construction is to take the LCM of all k[i]
// and set coins[i] = LCM / k[i]. Then every possible payout is exactly LCM.
// This works only if the total number of placed coins is smaller than LCM,
// which is equivalent to sum(LCM / k[i]) < LCM.

int main() {
	int t; cin >> t;
	while (t--) {
		int n; cin >> n;
		vector<int> array_k(n);
		for (int i = 0; i < n; i++)
		{
			cin >> array_k[i];
		}

		long long lcm_value = 1;
		for (int value : array_k)
		{
			lcm_value = lcm(lcm_value, (long long)value);
		}

		vector<int> array_coins(n);
		long long total = 0;
		for (int i = 0; i < n; i++)
		{
			array_coins[i] = (int)(lcm_value / array_k[i]);
			total += array_coins[i];
		}

		if (total >= lcm_value) cout << -1 << endl;
		else {
			for (int coin : array_coins)
			{
				cout << coin << " ";
			}
			cout << endl;
		}
	}
	return 0;
}

codeforces_div_2_round_951_problem_d:
#include <iostream>
#include <string>
#include <vector>
#include <cmath>
using namespace std;

// Problem: Codeforces Round 951 (Div. 2), D - Fixing a Binary String
// Link: https://codeforces.com/contest/1979/problem/D
//
// Summary:
// For each test case, a binary string s of length n and an integer k are given.
// We must choose p and apply exactly one operation: reverse the prefix of length
// p, then move that reversed prefix to the end. The resulting string must be
// k-proper: its first k characters are equal, and every character differs from
// the character k positions after it. If no valid p exists, print -1.
//
// Solve:
// A k-proper binary string is formed by blocks of length k, where each block has
// equal characters and adjacent blocks have opposite characters. This solution
// tries to choose p by looking at the suffix that will stay at the front after
// the operation and the reversed prefix that will be moved to the end. It counts
// the final run of equal characters, searches for a compatible cut position, and
// then verifies the produced string with the k-proper conditions. If no verified
// cut is found, the answer is -1.

string s; int n; int k;
bool verify() {
	bool val_return = true;
	for (int i = 1; i < k; i++)
	{
		if (s[i] != s[0]) {
			val_return = false;
			break;
		}
	}
	for (int i = 0; i < (n-k); i++)
	{
		if (s[i] == s[i + k]) {
			val_return = false;
			break;
		}
	}
	return val_return;
}
void change_s(int pot_p) {
	string s_aux = s;
	int aux_counter = 0;
	for (int i = (pot_p); i < n; i++)
	{
		s_aux[aux_counter] = s[i];
		aux_counter++;
	}
	for (int i = (pot_p - 1); i >= 0; i--)
	{
		s_aux[aux_counter] = s[i];
		aux_counter++;
	}
	s = s_aux;
}
bool case_1(int& pot, int counter_1, int& counter_2) {
	bool val_return = false;
	for (int i = 0; i < (n - counter_1); i++)
	{
		if (s[i] == s[n - 1]) {
			if (pot == -1) pot = i;
			counter_2++;
			if ((counter_2 + counter_1 == k)) {
				bool value_extra = s[i] != s[i + 1];
				if (value_extra == false) {
					if (i + k < n) {
						value_extra = true;
						for (int j = 1; j <= k; j++)
						{
							if (s[i + j] != s[i]) {
								value_extra = false;
								break;
							}
						}
					}
				}
				if (value_extra) {
					val_return = true;
					break;
				}
			}
		}
		else {
			pot = -1;
			counter_2 = 0;
		}
	}
	return val_return;
}
bool case_2(int& pot, int counter_1, int& counter_2) {
	counter_2 = 1;
	bool val_return = false;
	for (int i = 1; i < (n - counter_1); i++)
	{
		if (s[i] == s[i - 1]) {
			if (pot == -1) pot = i-1;
			counter_2++;
			if (counter_2 == 2 * k && s[i] != s[i + 1]) {
				val_return = true;
				counter_2 = (counter_2 / 2);
				break;
			}
		}
		else {
			pot = -1;
			counter_2 = 1;
		}
	}
	return val_return;
}
int change() {
	int p_return = -1;
	int counter_1 = 1;
	for (int i = (n - 2); i >= n - k; i--)
	{
		if (s[i] == s[n - 1]) counter_1++;
		else break;
	}
	if (counter_1 != k) {
		int pot = -1; int counter_2 = 0;
		bool value_case = case_1(pot, counter_1, counter_2);
		if (value_case == false) {
			value_case = case_2(pot, counter_1, counter_2);
		}
		if (value_case) {
			change_s(pot + counter_2);
			p_return = (pot + counter_2);
		}
	}
	else {
		int pot = -1; int counter_2 = 0;
		bool value_case = case_2(pot, counter_1, counter_2);
		if (value_case) {
			change_s(pot + counter_2);
			p_return = (pot + counter_2);
		}
		else {
			p_return = n;
		}
	}
	return p_return;
}

int main() {
	int t; cin >> t;
	while (t--) {
		cin >> n; cin >> k; cin >> s;
		int p = -1;
		if (n == k) {
			if (verify()) p = n;
		}
		else {
			p = change();
			if (p != -1) {
				if (verify() == false) p = -1;
			}
		}
		cout << p << endl;
	}
	return 0;
}

codeforces_div_2_round_953_problem_a:
#include <algorithm>
#include <iostream>
#include <vector>
using namespace std;

// Problem: Codeforces Round 953 (Div. 2), A - Alice and Books
// Link: https://codeforces.com/contest/1978/problem/A
//
// Summary:
// For each test case, an array of n book values is given. We must split the
// array into two non-empty consecutive parts and maximize the sum of the last
// value of each part.
//
// Solve:
// The last value of the second part is always a[n - 1]. To maximize the answer,
// choose the split so that the last value of the first part is the maximum value
// among a[0], a[1], ..., a[n - 2]. Therefore, the answer is a[n - 1] plus the
// maximum value before it.

int main() {
	int t; cin >> t;
	while (t--) {
		int n; cin >> n;
		vector<int> array_n(n);
		for (int i = 0; i < n; i++)
		{
			cin >> array_n[i];
		}
		int sol = array_n[n - 1] + *max_element(array_n.begin(), array_n.end() - 1);
		cout << sol << endl;
	}
	return 0;
}

codeforces_div_2_round_953_problem_b:
#include <iostream>
using namespace std;

// Problem: Codeforces Round 953 (Div. 2), B - New Bakery
// Link: https://codeforces.com/contest/1978/problem/B
//
// Summary:
// Bob sells n buns. Normally each bun costs a coins, but he may choose k buns
// for a promotion, where the first promoted bun costs b, the next b - 1, and so
// on. The remaining buns are sold at the normal price a. The goal is to maximize
// the total profit.
//
// Solve:
// Start from selling every bun at the normal price a. A promoted bun is useful
// only while its promoted price is greater than a, so the number (k) of useful
// promoted buns is min(n, b - a). Add the extra profit from those promoted buns:
// (b - a) + (b - a - 1) + ... (b - a - (b - a - 1)) = k * (b - a) - k * (k - 1) / 2

int main() {
	int t; cin >> t;
	while (t--) {
		int n; int a; int b;
		cin >> n >> a >> b;

		int k = min(n, max(0, b - a));
		long long sol = 1LL * n * a + 1LL * k * (b - a) - 1LL * k * (k - 1) / 2;
		cout << sol << endl;
	}
	return 0;
}

codeforces_div_2_round_953_problem_d:
#include <algorithm>
#include <iostream>
#include <vector>
using namespace std;

// Problem: Codeforces Round 953 (Div. 2), D - Elections
// Link: https://codeforces.com/contest/1978/problem/D
//
// Summary:
// There are n election candidates and c undecided votes. Candidate 0 receives
// all undecided votes among the remaining candidates. For each candidate i, find
// the minimum number of other candidates that must be removed so that candidate
// i becomes a winner.
//
// Solve:
// If every candidate before i is removed, candidate i becomes the first
// remaining candidate and receives all undecided votes plus the votes of those
// removed candidates. That value is prefix_sum[i] + c. If it is at least the
// maximum vote count on the right, removing the i previous candidates is enough.
// Otherwise, one more removal is needed for the strongest candidate on the
// right. The only exception is a candidate that already wins without removing
// anyone, whose answer is 0.

int main() {
	int t; cin >> t;
	while (t--) {
		int n; long long c;
		cin >> n >> c;

		vector<int> array_n(n);
		for (int i = 0; i < n; i++)
		{
			cin >> array_n[i];
		}

		vector<long long> array_prefix(n);
		array_prefix[0] = array_n[0];
		for (int i = 1; i < n; i++)
		{
			array_prefix[i] = array_prefix[i - 1] + array_n[i];
		}

		vector<int> array_right_max(n);
		array_right_max[n - 1] = 0;
		for (int i = n - 2; i >= 0; i--)
		{
			array_right_max[i] = max(array_n[i + 1], array_right_max[i + 1]);
		}

		long long initial_max = max(array_n[0] + c, (long long)array_right_max[0]);
		bool found_initial_winner = false;

		for (int i = 0; i < n; i++)
		{
			int sol;
			if (!found_initial_winner && array_n[i] + (i == 0 ? c : 0) >= initial_max) {
				sol = 0;
				found_initial_winner = true;
			}
			else if (array_prefix[i] + c >= array_right_max[i]) sol = i;
			else sol = i + 1;

			cout << sol << " ";
		}
		cout << endl;
	}
	return 0;
}

